14	 *  WHATSOEVER RESULTING FROM LOSS OF USE, DATA OR PROFITS, WHETHER IN AN
15	 *  ACTION OF CONTRACT, NEGLIGENCE OR OTHER TORTIOUS ACTION, ARISING OUT OF
16	 *  OR IN CONNECTION WITH THE USE OR PERFORMANCE OF THIS SOFTWARE.
17	 *
18	 *  ---
19	 *
20	 *  The Verilog frontend.
21	 *
22	 *  This frontend is using the AST frontend library (see frontends/ast/).
23	 *  Thus this frontend does not generate RTLIL code directly but creates an
24	 *  AST directly from the Verilog parse tree and then passes this AST to
25	 *  the AST frontend library.
26	 *
27	 *  ---
28	 *
29	 *  This file contains an ad-hoc parser for Verilog constants. The Verilog
30	 *  lexer does only recognize a constant but does not actually split it to its
31	 *  components. I.e. it just passes the Verilog code for the constant to the
32	 *  bison parser. The parser then uses the function const2ast() from this file
33	 *  to create an AST node for the constant.
34	 *
35	 */
36	
37	#include "verilog_frontend.h"
38	#include "kernel/log.h"
39	#include <string.h>
40	#include <math.h>
41	
42	YOSYS_NAMESPACE_BEGIN
43	
44	using namespace AST;
45	using namespace VERILOG_FRONTEND;
46	
47	void ConstParser::log_maybe_loc_error(std::string msg) {
48		log_file_error(*loc.begin.filename, loc.begin.line, "%s", msg);
49	}
50	
51	void ConstParser::log_maybe_loc_warn(std::string msg) {
52		log_file_warning(*loc.begin.filename, loc.begin.line, "%s", msg);
53	}
54	
55	// divide an arbitrary length decimal number by two and return the rest
56	int ConstParser::my_decimal_div_by_two(std::vector<uint8_t> &digits)
57	{
58		int carry = 0;
59		for (size_t i = 0; i < digits.size(); i++) {
60			if (digits[i] >= 10)
61				log_maybe_loc_error("Invalid use of [a-fxz?] in decimal constant.\n");
62			digits[i] += carry * 10;
63			carry = digits[i] % 2;
64			digits[i] /= 2;
65		}
66		while (!digits.empty() && !digits.front())
67			digits.erase(digits.begin());
68		return carry;
69	}
70	
71	// find the number of significant bits in a binary number (not including the sign bit)
72	int ConstParser::my_ilog2(int x)
73	{
74		int ret = 0;
75		while (x != 0 && x != -1) {
76			x = x >> 1;
77			ret++;
78		}
79		return ret;
80	}
81	
82	// parse a binary, decimal, hexadecimal or octal number with support for special bits ('x', 'z' and '?')
83	void ConstParser::my_strtobin(std::vector<RTLIL::State> &data, const char *str, int len_in_bits, int base, char case_type, bool is_unsized)
84	{
85		// all digits in string (MSB at index 0)
86		std::vector<uint8_t> digits;
87	
88		while (*str) {
89			if ('0' <= *str && *str <= '9')
90				digits.push_back(*str - '0');
91			else if ('a' <= *str && *str <= 'f')
92				digits.push_back(10 + *str - 'a');
93			else if ('A' <= *str && *str <= 'F')
94				digits.push_back(10 + *str - 'A');
95			else if (*str == 'x' || *str == 'X')
96				digits.push_back(0xf0);
97			else if (*str == 'z' || *str == 'Z' || *str == '?')
98				digits.push_back(0xf1);
99			str++;
100		}
101	
102		if (base == 10 && GetSize(digits) == 1 && digits.front() >= 0xf0)
103			base = 2;
104	
105		data.clear();
106	
107		if (base == 10) {
108			while (!digits.empty())
109				data.push_back(my_decimal_div_by_two(digits) ? State::S1 : State::S0);
110		} else {
111			int bits_per_digit = my_ilog2(base-1);
112			for (auto it = digits.rbegin(), e = digits.rend(); it != e; it++) {
113				if (*it > (base-1) && *it < 0xf0)
114					log_maybe_loc_error(stringf("Digit larger than %d used in in base-%d constant.\n",
115								base-1, base));
116				for (int i = 0; i < bits_per_digit; i++) {
117					int bitmask = 1 << i;
118					if (*it == 0xf0)
119						data.push_back(case_type == 'x' ? RTLIL::Sa : RTLIL::Sx);
120					else if (*it == 0xf1)
121						data.push_back(case_type == 'x' || case_type == 'z' ? RTLIL::Sa : RTLIL::Sz);
122					else
123						data.push_back((*it & bitmask) ? State::S1 : State::S0);
124				}
125			}
126		}
127	
128		int len = GetSize(data);
129		RTLIL::State msb = data.empty() ? State::S0 : data.back();
130	
131		if (len_in_bits < 0) {
132			if (len < 32)
133				data.resize(32, msb == State::S0 || msb == State::S1 ? RTLIL::S0 : msb);
134			return;
135		}
136	
137		if (is_unsized && (len > len_in_bits))
138			log_maybe_loc_error(stringf("Unsized constant must have width of 1 bit, but have %d bits!\n", len));
139	
140		for (len = len - 1; len >= 0; len--)
141			if (data[len] == State::S1)
142				break;
143		if (msb == State::S0 || msb == State::S1) {
144			len += 1;
145			data.resize(len_in_bits, State::S0);
146		} else {
147			len += 2;
148			data.resize(len_in_bits, msb);
149		}
150	
151		if (len_in_bits == 0)
152			log_maybe_loc_error("Illegal integer constant size of zero (IEEE 1800-2012, 5.7).\n");
153	
154		if (len > len_in_bits)
155			log_maybe_loc_warn(stringf("Literal has a width of %d bit, but value requires %d bit.\n",
156				len_in_bits, len));
157	}
158	// convert the Verilog code for a constant to an AST node
159	std::unique_ptr<AstNode> ConstParser::const2ast(std::string code, char case_type, bool warn_z)
160	{
161		if (warn_z) {
162			auto ret = const2ast(code, case_type);
163			if (ret != nullptr && std::find(ret->bits.begin(), ret->bits.end(), RTLIL::State::Sz) != ret->bits.end())
164				log_maybe_loc_warn("Yosys has only limited support for tri-state logic at the moment.\n");
165			return ret;
166		}
167	
168		const char *str = code.c_str();
169	
170		// Strings
171		if (*str == '"') {
172			int len = strlen(str) - 2;
173			std::vector<RTLIL::State> data;
174			data.reserve(len * 8);
175			for (int i = 0; i < len; i++) {
176				unsigned char ch = str[len - i];
177				for (int j = 0; j < 8; j++) {
178					data.push_back((ch & 1) ? State::S1 : State::S0);
179					ch = ch >> 1;
180				}
181			}
182			auto ast = AstNode::mkconst_bits(loc, data, false);
183			ast->str = code;
184			return ast;
185		}
186	
187		for (size_t i = 0; i < code.size(); i++)
188			if (code[i] == '_' || code[i] == ' ' || code[i] == '\t' || code[i] == '\r' || code[i] == '\n')
189				code.erase(code.begin()+(i--));
190		str = code.c_str();
191	
192		char *endptr;
193		long len_in_bits = strtol(str, &endptr, 10);
194	
195		// Simple base-10 integer
196		if (*endptr == 0) {
197			std::vector<RTLIL::State> data;
198			my_strtobin(data, str, -1, 10, case_type, false);
199			if (data.back() == State::S1)
200				data.push_back(State::S0);
201			return AstNode::mkconst_bits(loc, data, true);
202		}
203	
204		// unsized constant
205		if (str == endptr)
206			len_in_bits = -1;
207	
208		// The "<bits>'[sS]?[bodhBODH]<digits>" syntax
209		if (*endptr == '\'')
210		{
211			std::vector<RTLIL::State> data;
212			bool is_signed = false;
213			bool is_unsized = len_in_bits < 0;
214			if (*(endptr+1) == 's' || *(endptr+1) == 'S') {
215				is_signed = true;
216				endptr++;
217			}
218			switch (*(endptr+1))
219			{
220			case 'b':
221			case 'B':
222				my_strtobin(data, endptr+2, len_in_bits, 2, case_type, is_unsized);
223				break;
224			case 'o':
225			case 'O':
226				my_strtobin(data, endptr+2, len_in_bits, 8, case_type, is_unsized);
227				break;
228			case 'd':
229			case 'D':
230				my_strtobin(data, endptr+2, len_in_bits, 10, case_type, is_unsized);
231				break;
232			case 'h':
233			case 'H':
234				my_strtobin(data, endptr+2, len_in_bits, 16, case_type, is_unsized);
235				break;
236			default:
237				char next_char = char(tolower(*(endptr+1)));
238				if (next_char == '0' || next_char == '1' || next_char == 'x' || next_char == 'z') {
239					is_unsized = true;
240					my_strtobin(data, endptr+1, 1, 2, case_type, is_unsized);
241				} else {
242					return NULL;
243				}
244			}
245			if (len_in_bits < 0) {
246				if (is_signed && data.back() == State::S1)
247					data.push_back(State::S0);
248			}
249			return AstNode::mkconst_bits(loc, data, is_signed, is_unsized);
250		}
251	
252		return NULL;
253	}
254	
255	
256	YOSYS_NAMESPACE_END
