48	static std::list<std::string> output_code;
49	static std::list<std::string> input_buffer;
50	static size_t input_buffer_charp;
51	
52	static void return_char(char ch)
53	{
54		if (input_buffer_charp == 0)
55			input_buffer.push_front(std::string() + ch);
56		else
57			input_buffer.front()[--input_buffer_charp] = ch;
58	}
59	
60	static void insert_input(std::string str)
61	{
62		if (input_buffer_charp != 0) {
63			input_buffer.front() = input_buffer.front().substr(input_buffer_charp);
64			input_buffer_charp = 0;
65		}
66		input_buffer.push_front(str);
67	}
68	
69	static char next_char()
70	{
71		if (input_buffer.empty())
72			return 0;
73	
74		log_assert(input_buffer_charp <= input_buffer.front().size());
75		if (input_buffer_charp == input_buffer.front().size()) {
76			input_buffer_charp = 0;
77			input_buffer.pop_front();
78			return next_char();
79		}
80	
81		char ch = input_buffer.front()[input_buffer_charp++];
82		return ch == '\r' ? next_char() : ch;
83	}
84	
85	static std::string skip_spaces()
86	{
87		std::string spaces;
88		while (1) {
89			char ch = next_char();
90			if (ch == 0)
91				break;
92			if (ch != ' ' && ch != '\t') {
93				return_char(ch);
94				break;
95			}
96			spaces += ch;
97		}
98		return spaces;
99	}
100	
101	static std::string next_token(bool pass_newline = false)
102	{
103		std::string token;
104	
105		char ch = next_char();
106		if (ch == 0)
107			return token;
108	
109		token += ch;
110		if (ch == '\n') {
111			if (pass_newline) {
112				output_code.push_back(token);
113				return "";
114			}
115			return token;
116		}
117	
118		if (ch == ' ' || ch == '\t')
119		{
120			while ((ch = next_char()) != 0) {
121				if (ch != ' ' && ch != '\t') {
122					return_char(ch);
123					break;
124				}
125				token += ch;
126			}
127		}
128		else if (ch == '"')
129		{
130			while ((ch = next_char()) != 0) {
131				token += ch;
132				if (ch == '"')
133					break;
134				if (ch == '\\') {
135					if ((ch = next_char()) != 0)
136						token += ch;
137				}
138			}
139			if (token == "\"\"" && (ch = next_char()) != 0) {
140				if (ch == '"')
141					token += ch;
142				else
143					return_char(ch);
144			}
145		}
146		else if (ch == '\\')
147		{
148			while ((ch = next_char()) != 0) {
149				if (ch < 33 || ch > 126) {
150					return_char(ch);
151					break;
152				}
153				token += ch;
154			}
155		}
156		else if (ch == '/')
157		{
158			if ((ch = next_char()) != 0) {
159				if (ch == '/') {
160					token += '*';
161					char last_ch = 0;
162					while ((ch = next_char()) != 0) {
163						if (ch == '\n') {
164							return_char(ch);
165							break;
166						}
167						if (last_ch != '*' || ch != '/') {
168							token += ch;
169							last_ch = ch;
170						}
171					}
172					token += " */";
173				}
174				else if (ch == '*') {
175					token += '*';
176					int newline_count = 0;
177					char last_ch = 0;
178					while ((ch = next_char()) != 0) {
179						if (ch == '\n') {
180							newline_count++;
181							token += ' ';
182						} else
183							token += ch;
184						if (last_ch == '*' && ch == '/')
185							break;
186						last_ch = ch;
187					}
188					while (newline_count-- > 0)
189						return_char('\n');
190				}
191				else
192					return_char(ch);
193			}
194		}
195		else
196		{
197			const char *ok = "abcdefghijklmnopqrstuvwxyz_ABCDEFGHIJKLMNOPQRSTUVWXYZ$0123456789";
198			if (ch == '`' || strchr(ok, ch) != NULL)
199			{
200				char first = ch;
201				ch = next_char();
202				if (first == '`' && (ch == '"' || ch == '`')) {
203					token += ch;
204				} else do {
205						if (strchr(ok, ch) == NULL) {
206							return_char(ch);
207							break;
208						}
209						token += ch;
210					} while ((ch = next_char()) != 0);
211			}
212		}
213		return token;
214	}
