229	static bool all_white(const std::string &str)
230	{
231		for (char c : str)
232			if (!isspace(c))
233				return false;
234		return true;
235	}
236	
237	struct arg_map_t
238	{
239		arg_map_t()
240		{}
241	
242		void add_arg(const std::string &name, const char *default_value)
243		{
244			if (find(name)) {
245				log_error("Duplicate macro arguments with name `%s'.\n", name);
246			}
247	
248			name_to_pos[name] = args.size();
249			args.push_back(macro_arg_t(name, default_value));
250		}
251	
252		// Find an argument by name; return nullptr if it doesn't exist. If pos is not null, write
253		// the argument's position to it on success.
254		const macro_arg_t *find(const std::string &name, int *pos = nullptr) const
255		{
256			auto it = name_to_pos.find(name);
257			if (it == name_to_pos.end())
258				return nullptr;
259	
260			if (pos) *pos = it->second;
261			return &args[it->second];
262		}
263	
264		// Construct the name for the local macro definition we use for the given argument
265		// (something like macro_foobar_arg2). This doesn't include the leading backtick.
266		static std::string str_token(const std::string &macro_name, int pos)
267		{
268			return stringf("macro_%s_arg%d", macro_name, pos);
269		}
270	
271		// Return definitions for the macro arguments (so that substituting in the macro body and
272		// then performing macro expansion will do argument substitution properly).
273		std::vector<std::pair<std::string, std::string>>
274		get_vals(const std::string &macro_name, const std::vector<std::string> &arg_vals) const
275		{
276			std::vector<std::pair<std::string, std::string>> ret;
277			for (int i = 0; i < GetSize(args); ++ i) {
278				// The SystemVerilog rules are:
279				//
280				//   - If the call site specifies an argument and it's not whitespace, use
281				//     it.
282				//
283				//   - Otherwise, if the argument has a default value, use it.
284				//
285				//   - Otherwise, if the call site specified whitespace, use that.
286				//
287				//   - Otherwise, error.
288				const std::string *dflt = nullptr;
289				if (args[i].has_default)
290					dflt = &args[i].default_value;
291	
292				const std::string *given = nullptr;
293				if (i < GetSize(arg_vals))
294					given = &arg_vals[i];
295	
296				const std::string *val = nullptr;
297				if (given && (! (dflt && all_white(*given))))
298					val = given;
299				else if (dflt)
300					val = dflt;
301				else if (given)
302					val = given;
303				else
304					log_error("Cannot expand macro `%s by giving only %d argument%s "
305					          "(argument %d has no default).\n",
306					          macro_name.c_str(), GetSize(arg_vals),
307					          (GetSize(arg_vals) == 1 ? "" : "s"), i + 1);
308	
309				assert(val);
310				ret.push_back(std::make_pair(str_token(macro_name, i), * val));
311			}
312			return ret;
313		}
314	
315	
316		std::vector<macro_arg_t>   args;
317		std::map<std::string, int> name_to_pos;
318	};
