405	// Read tokens to get one argument (either a macro argument at a callsite or a default argument in a
406	// macro definition). Writes the argument to dest. Returns true if we finished with ')' (the end of
407	// the argument list); false if we finished with ','.
408	static bool read_argument(std::string &dest)
409	{
410		skip_spaces();
411		std::vector<char> openers;
412		for (;;) {
413			std::string tok = next_token(true);
414			if (tok == ")") {
415				if (openers.empty()) {
416					while (dest.size() && (dest.back() == ' ' || dest.back() == '\t'))
417						dest = dest.substr(0, dest.size() - 1);
418					return true;
419				}
420				if (openers.back() != '(')
421					log_error("Mismatched brackets in macro argument: %c and %c.\n",
422					          openers.back(), tok[0]);
423	
424				openers.pop_back();
425				dest += tok;
426				continue;
427			}
428			if (tok == "]") {
429				char opener = openers.empty() ? '(' : openers.back();
430				if (opener != '[')
431					log_error("Mismatched brackets in macro argument: %c and %c.\n",
432					          opener, tok[0]);
433	
434				openers.pop_back();
435				dest += tok;
436				continue;
437			}
438			if (tok == "}") {
439				char opener = openers.empty() ? '(' : openers.back();
440				if (opener != '{')
441					log_error("Mismatched brackets in macro argument: %c and %c.\n",
442					          opener, tok[0]);
443	
444				openers.pop_back();
445				dest += tok;
446				continue;
447			}
448	
449			if (tok == "," && openers.empty()) {
450				return false;
451			}
452	
453			if (tok == "(" || tok == "[" || tok == "{")
454				openers.push_back(tok[0]);
455	
456			dest += tok;
457		}
458	}
