460	using macro_arg_stack_t = std::stack<std::pair<std::string, define_body_t>>;
461	
462	static void restore_macro_arg(define_map_t &defines, macro_arg_stack_t &macro_arg_stack)
463	{
464		log_assert(!macro_arg_stack.empty());
465		auto &overwritten_arg = macro_arg_stack.top();
466		defines.add(overwritten_arg.first, overwritten_arg.second);
467		macro_arg_stack.pop();
468	}
469	
470	static bool try_expand_macro(define_map_t &defines, macro_arg_stack_t &macro_arg_stack, std::string &tok)
471	{
472		if (tok == "`\"") {
473			std::string literal("\"");
474			// Expand string literal
475			while (!input_buffer.empty()) {
476				std::string ntok = next_token();
477				if (ntok == "`\"") {
478					insert_input(literal+"\"");
479					return true;
480				} else if (!try_expand_macro(defines, macro_arg_stack, ntok)) {
481						literal += ntok;
482				}
483			}
484			return false; // error - unmatched `"
485		}
486	
487		if (tok == "``") {
488			// Swallow `` in macro expansion
489			return true;
490		}
491	
492		if (tok.size() <= 1 || tok[0] != '`')
493			return false;
494	
495		// This token looks like a macro name (`foo).
496		std::string macro_name = tok.substr(1);
497		const define_body_t *body = defines.find(tok.substr(1));
498	
499		if (! body) {
500			// Apparently not a name we know.
501			return false;
502		}
503	
504		std::string name = tok.substr(1);
505		std::string skipped_spaces = skip_spaces();
506		tok = next_token(false);
507		if (body->has_args) {
508			if (tok != "(") {
509				if (tok.size() == 1 && iscntrl(tok[0])) {
510					char buf[5];
511					snprintf(buf, sizeof(buf), "\\x%02x", tok[0]);
512					tok = buf;
513				}
514				log_error("Expected to find '(' to begin macro arguments for '%s', but instead found '%s'\n",
515					name.c_str(), tok.c_str());
516			}
517			std::vector<std::string> args;
518			bool done = false;
519			while (!done) {
520				std::string arg;
521				done = read_argument(arg);
522				args.push_back(arg);
523			}
524			for (const auto &pr : body->args.get_vals(name, args)) {
525				if (const define_body_t *existing = defines.find(pr.first)) {
526					macro_arg_stack.push({pr.first, *existing});
527					insert_input("`__restore_macro_arg ");
528				}
529				defines.add(pr.first, pr.second);
530			}
531		} else {
532			insert_input(tok);
533			insert_input(skipped_spaces);
534		}
535		insert_input(body->body);
536		return true;
537	}
