539	// Read the arguments for a `define preprocessor directive with formal arguments. This is called
540	// just after reading the token containing "(". Returns the number of newlines to emit afterwards to
541	// keep line numbers in sync, together with the map from argument name to data (pos and default
542	// value).
543	static std::pair<int, arg_map_t>
544	read_define_args()
545	{
546		// Each argument looks like one of the following:
547		//
548		//     identifier
549		//     identifier = default_text
550		//     identifier =
551		//
552		// The first example is an argument with no default value. The second is an argument whose
553		// default value is default_text. The third is an argument with default value the empty
554		// string.
555	
556		int newline_count = 0;
557		arg_map_t args;
558	
559		// FSM state.
560		//
561		//   0: At start of identifier
562		//   1: After identifier (stored in arg_name)
563		//   2: After closing paren
564		int state = 0;
565	
566		std::string arg_name, default_val;
567	
568		skip_spaces();
569		for (;;) {
570			if (state == 2)
571				// We've read the closing paren.
572				break;
573	
574			std::string tok = next_token();
575	
576			// Cope with escaped EOLs
577			if (tok == "\\") {
578				char ch = next_char();
579				if (ch == '\n') {
580					// Eat the \, the \n and any trailing space and keep going.
581					skip_spaces();
582					continue;
583				} else {
584					// There aren't any other situations where a backslash makes sense.
585					log_error("Backslash in macro arguments (not at end of line).\n");
586				}
587			}
588	
589			switch (state) {
590			case 0:
591				// At start of argument. If the token is ')', we've presumably just seen
592				// something like "`define foo() ...". Set state to 2 to finish. Otherwise,
593				// the token should be a valid simple identifier, but we'll allow anything
594				// here.
595				if (tok == ")") {
596					state = 2;
597				} else {
598					arg_name = tok;
599					state = 1;
600				}
601				skip_spaces();
602				break;
603	
604			case 1:
605				// After argument. The token should either be an equals sign or a comma or
606				// closing paren.
607				if (tok == "=") {
608					std::string default_val;
609					//Read an argument into default_val and set state to 2 if we're at
610					// the end; 0 if we hit a comma.
611					state = read_argument(default_val) ? 2 : 0;
612					args.add_arg(arg_name, default_val.c_str());
613					skip_spaces();
614					break;
615				}
616				if (tok == ",") {
617					// Take the identifier as an argument with no default value.
618					args.add_arg(arg_name, nullptr);
619					state = 0;
620					skip_spaces();
621					break;
622				}
623				if (tok == ")") {
624					// As with comma, but set state to 2 (end of args)
625					args.add_arg(arg_name, nullptr);
626					state = 2;
627					skip_spaces();
628					break;
629				}
630				log_error("Trailing contents after identifier in macro argument `%s': "
631					  "expected '=', ',' or ')'.\n",
632					  arg_name.c_str());
633	
634			default:
635				// The only FSM states are 0-2 and we dealt with 2 at the start of the loop.
636				log_assert(false);
637			}
638		}
639	
640		return std::make_pair(newline_count, args);
641	}
642	
643	// Read a `define preprocessor directive. This is called just after reading the token containing
644	// "`define".
645	static void
646	read_define(const std::string &filename,
647	            define_map_t      &defines_map,
648	            define_map_t      &global_defines_cache)
649	{
650		std::string name, value;
651		arg_map_t args;
652	
653		skip_spaces();
654		name = next_token(true);
655	
656		bool here_doc_mode = false;
657		int newline_count = 0;
658	
659		// The FSM state starts at 0. If it sees space (or enters here_doc_mode), it assumes this is
660		// a macro without formal arguments and jumps to state 1.
661		//
662		// In state 0, if it sees an opening parenthesis, it assumes this is a macro with formal
663		// arguments. It reads the arguments with read_define_args() and then jumps to state 2.
664		//
665		// In states 1 or 2, the FSM reads tokens to the end of line (or end of here_doc): this is
666		// the body of the macro definition.
667		int state = 0;
668	
669		if (skip_spaces() != "")
670			state = 1;
671	
672		for (;;) {
673			std::string tok = next_token();
674			if (tok.empty())
675				break;
676	
677			// printf("define-tok: >>%s<<\n", tok != "\n" ? tok.c_str() : "NEWLINE");
678	
679			if (tok == "\"\"\"") {
680				here_doc_mode = !here_doc_mode;
681				continue;
682			}
683	
684			if (state == 0 && tok == "(") {
685				auto pr = read_define_args();
686				newline_count += pr.first;
687				args = pr.second;
688	
689				state = 2;
690				continue;
691			}
692	
693			// This token isn't an opening parenthesis immediately following the macro name, so
694			// it's presumably at or after the start of the macro body. If state isn't already 2
695			// (which would mean we'd parsed an argument list), set it to 1.
696			if (state == 0) {
697				state = 1;
698			}
699	
700			if (tok == "\n") {
701				if (here_doc_mode) {
702					value += " ";
703					newline_count++;
704				} else {
705					return_char('\n');
706					break;
707				}
708				continue;
709			}
710	
711			if (tok == "\\") {
712				char ch = next_char();
713				if (ch == '\n') {
714					value += " ";
715					newline_count++;
716				} else {
717					value += std::string("\\");
718					return_char(ch);
719				}
720				continue;
721			}
722	
723			// Is this token the name of a macro argument? If so, replace it with a magic symbol
724			// that we'll replace with the argument value.
725			int arg_pos;
726			if (args.find(tok, &arg_pos)) {
727				value += '`' + args.str_token(name, arg_pos);
728				continue;
729			}
730	
731			// This token is nothing special. Insert it verbatim into the macro body.
732			value += tok;
733		}
734	
735		// Append some newlines so that we don't mess up line counts in error messages.
736		while (newline_count-- > 0)
737			return_char('\n');
738	
739		if (strchr("abcdefghijklmnopqrstuvwxyz_ABCDEFGHIJKLMNOPQRSTUVWXYZ$0123456789", name[0])) {
740			// printf("define: >>%s<< -> >>%s<<\n", name.c_str(), value.c_str());
741			defines_map.add(name, value, (state == 2) ? &args : nullptr);
742			global_defines_cache.add(name, value, (state == 2) ? &args : nullptr);
743		} else {
744			log_file_error(filename, 0, "Invalid name for macro definition: >>%s<<.\n", name);
745		}
746	}
747	
748	std::string
749	frontend_verilog_preproc(std::istream                 &f,
750	                         std::string                   filename,
751	                         const define_map_t           &pre_defines,
752	                         define_map_t                 &global_defines_cache,
753	                         const std::list<std::string> &include_dirs,
754	                         ParseState                   &parse_state,
755	                         ParseMode                    &parse_mode)
756	{
757		define_map_t defines;
758		defines.merge(pre_defines);
759		defines.merge(global_defines_cache);
760	
761		macro_arg_stack_t macro_arg_stack;
762		std::vector<std::string> filename_stack;
763		// We are inside pass_level levels of satisfied ifdefs, and then within
764		// fail_level levels of unsatisfied ifdefs.  The unsatisfied ones are
765		// always within satisfied ones — even if some condition within is true,
766		// the parent condition failing renders it moot.
767		int ifdef_fail_level = 0;
768		int ifdef_pass_level = 0;
769		// For the outermost unsatisfied ifdef, true iff that ifdef already
770		// had a satisfied branch, and further elsif/else branches should be
771		// considered unsatisfied even if the condition is true.
772		// Meaningless if ifdef_fail_level == 0.
773		bool ifdef_already_satisfied = false;
774	
775		output_code.clear();
776		input_buffer.clear();
777		input_buffer_charp = 0;
778	
779		input_file(f, filename);
780	
781		while (!input_buffer.empty())
782		{
783			std::string tok = next_token();
784			// printf("token: >>%s<<\n", tok != "\n" ? tok.c_str() : "NEWLINE");
785	
786			if (tok == "`endif") {
787				if (ifdef_fail_level > 0)
788					ifdef_fail_level--;
789				else if (ifdef_pass_level > 0)
790					ifdef_pass_level--;
791				else
792					log_error("Found %s outside of macro conditional branch!\n", tok);
793				continue;
794			}
795	
796			if (tok == "`else") {
797				if (ifdef_fail_level == 0) {
798					if (ifdef_pass_level == 0)
799						log_error("Found %s outside of macro conditional branch!\n", tok);
800					ifdef_pass_level--;
801					ifdef_fail_level = 1;
802					ifdef_already_satisfied = true;
803				} else if (ifdef_fail_level == 1 && !ifdef_already_satisfied) {
804					ifdef_fail_level = 0;
805					ifdef_pass_level++;
806					ifdef_already_satisfied = true;
807				}
808				continue;
809			}
810	
811			if (tok == "`elsif") {
812				skip_spaces();
813				std::string name = next_token(true);
814				if (ifdef_fail_level == 0) {
815					if (ifdef_pass_level == 0)
816						log_error("Found %s outside of macro conditional branch!\n", tok);
817					ifdef_pass_level--;
818					ifdef_fail_level = 1;
819					ifdef_already_satisfied = true;
820				} else if (ifdef_fail_level == 1 && !ifdef_already_satisfied && defines.find(name)) {
821					ifdef_fail_level = 0;
822					ifdef_pass_level++;
823					ifdef_already_satisfied = true;
824				}
825				continue;
826			}
827	
828			if (tok == "`ifdef") {
829				skip_spaces();
830				std::string name = next_token(true);
831				if (ifdef_fail_level > 0 || !defines.find(name)) {
832					ifdef_fail_level++;
833				} else {
834					ifdef_pass_level++;
835					ifdef_already_satisfied = true;
836				}
837				if (ifdef_fail_level == 1)
838					ifdef_already_satisfied = false;
839				continue;
840			}
841	
842			if (tok == "`ifndef") {
843				skip_spaces();
844				std::string name = next_token(true);
845				if (ifdef_fail_level > 0 || defines.find(name)) {
846					ifdef_fail_level++;
847				} else {
848					ifdef_pass_level++;
849					ifdef_already_satisfied = true;
850				}
851				if (ifdef_fail_level == 1)
852					ifdef_already_satisfied = false;
853				continue;
854			}
855	
856			if (ifdef_fail_level > 0) {
857				if (tok == "\n")
858					output_code.push_back(tok);
859				continue;
860			}
861	
862			if (tok == "`include") {
863				skip_spaces();
864				std::string fn = next_token(true);
865				while (try_expand_macro(defines, macro_arg_stack, fn)) {
866					fn = next_token();
867				}
868				while (1) {
869					size_t pos = fn.find('"');
870					if (pos == std::string::npos)
871						break;
872					if (pos == 0)
873						fn = fn.substr(1);
874					else
875						fn = fn.substr(0, pos) + fn.substr(pos+1);
876				}
877				std::ifstream ff;
878				ff.clear();
879				std::string fixed_fn = fn;
880				ff.open(fixed_fn.c_str());
881	
882				bool filename_path_sep_found;
883				bool fn_relative;
884	#ifdef _WIN32
885				// Both forward and backslash are acceptable separators on Windows.
886				filename_path_sep_found = (filename.find_first_of("/\\") != std::string::npos);
887				// Easier just to invert the check for an absolute path (e.g. C:\ or C:/)
888				fn_relative = !(fn[1] == ':' && (fn[2] == '/' || fn[2] == '\\'));
889	#else
890				filename_path_sep_found = (filename.find('/') != std::string::npos);
891				fn_relative = (fn[0] != '/');
892	#endif
893	
894				if (ff.fail() && fn.size() > 0 && fn_relative && filename_path_sep_found) {
895					// if the include file was not found, it is not given with an absolute path, and the
896					// currently read file is given with a path, then try again relative to its directory
897					ff.clear();
898					fixed_fn = parent_from_file_path(filename) + fn;
899					ff.open(fixed_fn);
900				}
901				if (ff.fail() && fn.size() > 0 && fn_relative) {
902					// if the include file was not found and it is not given with an absolute path, then
903					// search it in the include path
904					for (auto incdir : include_dirs) {
905						ff.clear();
906						fixed_fn = incdir + '/' + fn;
907						ff.open(fixed_fn);
908						if (!ff.fail()) break;
909					}
910				}
911				if (ff.fail()) {
912					output_code.push_back("`file_notfound " + fn);
913				} else {
914					input_file(ff, fixed_fn);
915					yosys_input_files.insert(fixed_fn);
916				}
917				continue;
918			}
919	
920			if (tok == "`file_push") {
921				skip_spaces();
922				std::string fn = next_token(true);
923				if (!fn.empty() && fn.front() == '"' && fn.back() == '"')
924					fn = fn.substr(1, fn.size()-2);
925				output_code.push_back(tok + " \"" + fn + "\"");
926				filename_stack.push_back(filename);
927				filename = fn;
928				continue;
929			}
930	
931			if (tok == "`file_pop") {
932				output_code.push_back(tok);
933				filename = filename_stack.back();
934				filename_stack.pop_back();
935				continue;
936			}
937	
938			if (tok == "`define") {
939				read_define(filename, defines, global_defines_cache);
940				continue;
941			}
942	
943			if (tok == "`undef") {
944				std::string name;
945				skip_spaces();
946				name = next_token(true);
947				// printf("undef: >>%s<<\n", name.c_str());
948				defines.erase(name);
949				global_defines_cache.erase(name);
950				continue;
951			}
952	
953			if (tok == "`timescale") {
954				skip_spaces();
955				while (!tok.empty() && tok != "\n")
956					tok = next_token(true);
957				if (tok == "\n")
958					return_char('\n');
959				continue;
960			}
961	
962			if (tok == "`resetall") {
963				parse_state.default_nettype_wire = true;
964				continue;
965			}
966	
967			if (tok == "`undefineall" && parse_mode.sv) {
968				defines.clear();
969				global_defines_cache.clear();
970				continue;
971			}
972	
973			if (tok == "`__restore_macro_arg") {
974				restore_macro_arg(defines, macro_arg_stack);
975				continue;
976			}
977	
978			if (try_expand_macro(defines, macro_arg_stack, tok))
979				continue;
980	
981			output_code.push_back(tok);
982		}
983	
984		if (ifdef_fail_level > 0 || ifdef_pass_level > 0) {
985			log_error("Unterminated preprocessor conditional!\n");
986		}
987	
988		std::string output;
989		for (auto &str : output_code)
990			output += str;
991	
992		output_code.clear();
993		input_buffer.clear();
994		input_buffer_charp = 0;
995	
996		return output;
997	}
998	
999	YOSYS_NAMESPACE_END
1000

