441					flag_overwrite = true;
442					continue;
443				}
444				if (arg == "-defer") {
445					flag_defer = true;
446					continue;
447				}
448				if (arg == "-noautowire") {
449					parse_state.default_nettype_wire = false;
450					continue;
451				}
452				if (arg == "-setattr" && argidx+1 < args.size()) {
453					attributes.push_back(RTLIL::escape_id(args[++argidx]));
454					continue;
455				}
456				if (arg == "-relativeshare") {
457					flag_relative_share = true;
458					log_experimental("read_verilog -relativeshare");
459					continue;
460				}
461				if (arg == "-D" && argidx+1 < args.size()) {
462					std::string name = args[++argidx], value;
463					size_t equal = name.find('=');
464					if (equal != std::string::npos) {
465						value = name.substr(equal+1);
466						name = name.substr(0, equal);
467					}
468					defines_map.add(name, value);
469					continue;
470				}
471				if (arg.compare(0, 2, "-D") == 0) {
472					size_t equal = arg.find('=', 2);
473					std::string name = arg.substr(2, equal-2);
474					std::string value;
475					if (equal != std::string::npos)
476						value = arg.substr(equal+1);
477					defines_map.add(name, value);
478					continue;
479				}
480				if (arg == "-I" && argidx+1 < args.size()) {
481					include_dirs.push_back(args[++argidx]);
482					continue;
483				}
484				if (arg.compare(0, 2, "-I") == 0) {
485					include_dirs.push_back(arg.substr(2));
486					continue;
487				}
488				break;
489			}
490	
491			if (parse_mode.formal || !flag_nosynthesis)
492				defines_map.add(parse_mode.formal ? "FORMAL" : "SYNTHESIS", "1");
493	
494			extra_args(f, filename, args, argidx);
495	
496			log_header(design, "Executing Verilog-2005 frontend: %s\n", filename);
497	
498			log("Parsing %s%s input from `%s' to AST representation.\n",
499					parse_mode.formal ? "formal " : "", parse_mode.sv ? "SystemVerilog" : "Verilog", filename.c_str());
500	
501			if (flag_relative_share) {
502				auto share_path = proc_share_dirname();
503				if (filename.substr(0, share_path.length()) == share_path)
504					filename = std::string("+/") + filename.substr(share_path.length());
505				log("new filename %s\n", filename.c_str());
506			}
507			AST::sv_mode_but_global_and_used_for_literally_one_condition = parse_mode.sv;
508			std::string code_after_preproc;
509	
510			parse_state.lexin = f;
511			if (!flag_nopp) {
512				code_after_preproc = frontend_verilog_preproc(*f, filename, defines_map, *design->verilog_defines, include_dirs, parse_state, parse_mode);
513				if (flag_ppdump)
514					log("-- Verilog code after preprocessor --\n%s-- END OF DUMP --\n", code_after_preproc);
515				parse_state.lexin = new std::istringstream(code_after_preproc);
516			}
517	
518			auto filename_shared = std::make_shared<std::string>(filename);
519			auto top_loc = Location();
520			top_loc.begin.filename = filename_shared;
521			parse_state.current_ast = new AST::AstNode(top_loc, AST::AST_DESIGN);
522			VerilogLexer lexer(&parse_state, &parse_mode, filename_shared);
523			frontend_verilog_yy::parser parser(&lexer, &parse_state, &parse_mode);
524			lexer.set_debug(flag_debug_lexer);
525			parser.set_debug_level(flag_debug_parser ? 1 : 0);
526	
527			// make package typedefs available to parser
528			add_package_types(parse_state.pkg_user_types, design->verilog_packages);
529	
530			UserTypeMap global_types_map;
531			for (auto& def : design->verilog_globals) {
532				if (def->type == AST::AST_TYPEDEF) {
533					global_types_map[def->str] = def.get();
534				}
535			}
536	
537			log_assert(parse_state.user_type_stack.empty());
538			// use previous global typedefs as bottom level of user type stack
539			parse_state.user_type_stack.push_back(std::move(global_types_map));
540			// add a new empty type map to allow overriding existing global definitions
541			parse_state.user_type_stack.push_back(UserTypeMap());
542	
543			if (flag_yydebug) {
544				lexer.set_debug(true);
545				parser.set_debug_level(1);
546			}
547			parser.parse();
548			// frontend_verilog_yyset_lineno(1);
549	
550			for (auto &child : parse_state.current_ast->children) {
551				if (child->type == AST::AST_MODULE)
552					for (auto &attr : attributes)
553						if (child->attributes.count(attr) == 0)
554							child->attributes[attr] = AST::AstNode::mkconst_int(top_loc, 1, false);
555			}
556	
557			if (flag_nodpi)
558				error_on_dpi_function(parse_state.current_ast);
559	
560			AST::process(design, parse_state.current_ast, flag_nodisplay, flag_dump_ast1, flag_dump_ast2, flag_no_dump_ptr, flag_dump_vlog1, flag_dump_vlog2, flag_dump_rtlil, flag_nolatches,
561					flag_nomeminit, flag_nomem2reg, flag_mem2reg, flag_noblackbox, parse_mode.lib, flag_nowb, flag_noopt, flag_icells, flag_pwires, flag_nooverwrite, flag_overwrite, flag_defer, parse_state.default_nettype_wire);
562	
563	
564			if (!flag_nopp)
565				delete parse_state.lexin;
566	
567			// only the previous and new global type maps remain
568			log_assert(parse_state.user_type_stack.size() == 2);
569			parse_state.user_type_stack.clear();
570	
571			delete parse_state.current_ast;
572			parse_state.current_ast = NULL;
573	
574			log("Successfully finished Verilog frontend.\n");
575		}
