601		void execute(std::vector<std::string> args, RTLIL::Design*) override
602		{
603			if (args.size() < 2)
604				cmd_error(args, 1, "Missing argument.");
605	
606			if (args[1] == "-add") {
607				verilog_defaults.insert(verilog_defaults.end(), args.begin()+2, args.end());
608				return;
609			}
610	
611			if (args.size() != 2)
612				cmd_error(args, 2, "Extra argument.");
613	
614			if (args[1] == "-clear") {
615				verilog_defaults.clear();
616				return;
617			}
618	
619			if (args[1] == "-push") {
620				verilog_defaults_stack.push_back(verilog_defaults);
621				return;
622			}
623	
624			if (args[1] == "-pop") {
625				if (verilog_defaults_stack.empty()) {
626					verilog_defaults.clear();
627				} else {
628					verilog_defaults.swap(verilog_defaults_stack.back());
629					verilog_defaults_stack.pop_back();
630				}
631				return;
632			}
633		}
634	} VerilogDefaults;
