660		void execute(std::vector<std::string> args, RTLIL::Design *design) override
661		{
662			size_t argidx;
663			for (argidx = 1; argidx < args.size(); argidx++) {
664				std::string arg = args[argidx];
665				if (arg == "-D" && argidx+1 < args.size()) {
666					std::string name = args[++argidx], value;
667					size_t equal = name.find('=');
668					if (equal != std::string::npos) {
669						value = name.substr(equal+1);
670						name = name.substr(0, equal);
671					}
672					design->verilog_defines->add(name, value);
673					continue;
674				}
675				if (arg.compare(0, 2, "-D") == 0) {
676					size_t equal = arg.find('=', 2);
677					std::string name = arg.substr(2, equal-2);
678					std::string value;
679					if (equal != std::string::npos)
680						value = arg.substr(equal+1);
681					design->verilog_defines->add(name, value);
682					continue;
683				}
684				if (arg == "-U" && argidx+1 < args.size()) {
685					std::string name = args[++argidx];
686					design->verilog_defines->erase(name);
687					continue;
688				}
689				if (arg.compare(0, 2, "-U") == 0) {
690					std::string name = arg.substr(2);
691					design->verilog_defines->erase(name);
692					continue;
693				}
694				if (arg == "-reset") {
695					design->verilog_defines->clear();
696					continue;
697				}
698				if (arg == "-list") {
699					design->verilog_defines->log();
700					continue;
701				}
702				break;
703			}
704	
705			if (args.size() != argidx)
706				cmd_error(args, argidx, "Extra argument.");
707		}
708	} VerilogDefines;
