710	static void parse_file_list(const std::string &file_list_path, RTLIL::Design *design, bool relative_to_file_list_path)
711	{
712		std::ifstream flist(file_list_path);
713		if (!flist.is_open()) {
714			log_error("Verilog file list file does not exist");
715			exit(1);
716		}
717	
718		std::filesystem::path file_list_parent_dir = std::filesystem::path(file_list_path).parent_path();
719	
720		std::string v_file_name;
721		while (std::getline(flist, v_file_name)) {
722			if (v_file_name.empty()) {
723				continue;
724			}
725	
726			std::filesystem::path verilog_file_path;
727			if (relative_to_file_list_path) {
728				verilog_file_path = file_list_parent_dir / v_file_name;
729			} else {
730				verilog_file_path = std::filesystem::current_path() / v_file_name;
731			}
732	
733			bool is_sv = (verilog_file_path.extension() == ".sv");
734	
735			std::vector<std::string> read_verilog_cmd = {"read_verilog", "-defer"};
736			if (is_sv) {
737				read_verilog_cmd.push_back("-sv");
738			}
739			read_verilog_cmd.push_back(verilog_file_path.string());
740			Pass::call(design, read_verilog_cmd);
741		}
742	
743		flist.close();
744	}
745	
746	struct VerilogFileList : public Pass {
747		VerilogFileList() : Pass("read_verilog_file_list", "parse a Verilog file list") {}
748		void help() override
749		{
750			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
751			log("\n");
752			log("    read_verilog_file_list [options]\n");
753			log("\n");
754			log("Parse a Verilog file list, and pass the list of Verilog files to read_verilog\n");
755			log("command\n");
756			log("\n");
757			log("    -F file_list_path\n");
758			log("        File list file contains list of Verilog files to be parsed, any path is\n");
759			log("        treated relative to the file list file\n");
760			log("\n");
761			log("    -f file_list_path\n");
762			log("        File list file contains list of Verilog files to be parsed, any path is\n");
763			log("        treated relative to current working directroy\n");
764			log("\n");
765		}
766	
767		void execute(std::vector<std::string> args, RTLIL::Design *design) override
768		{
769			size_t argidx;
770			for (argidx = 1; argidx < args.size(); argidx++) {
771				std::string arg = args[argidx];
772				if (arg == "-F" && argidx + 1 < args.size()) {
773					std::string file_list_path = args[++argidx];
774					parse_file_list(file_list_path, design, true);
775					continue;
776				}
777				if (arg == "-f" && argidx + 1 < args.size()) {
778					std::string file_list_path = args[++argidx];
779					parse_file_list(file_list_path, design, false);
780					continue;
781				}
782				break;
783			}
784	
785			extra_args(args, argidx, design, false);
786		}
787	} VerilogFilelist;
788	
789	YOSYS_NAMESPACE_END
790

